/**
 * POST /api/spirit-animal — Spirit animal guide creation flow.
 *
 * Two modes of operation:
 *  1. No body (or empty body) — returns 6 conversational quiz questions generated by Gemini.
 *  2. Body contains `answers: { question, answer }[]` — evaluates answers, picks the best-fit
 *     spirit animal and a variant from the curated set, and returns { animal, description, svg }.
 *
 * Each animal has multiple SVG variants so "Try again" can produce visibly different outputs.
 * Gemini also picks a variant index so repeated evaluations feel different.
 */

import { Router, type IRouter } from "express";
import { z } from "zod";
import { ai } from "@workspace/integrations-gemini-ai";

const router: IRouter = Router();

const MODEL = "gemini-2.5-flash";

