const ANIMALS = Object.keys(SVG_VARIANTS);

// Helper: pick a variant for an animal.
// `seed` is clamped to valid bounds so negative/non-integer values from Gemini are safe.
function pickVariant(animal: string, seed?: number): string {
  const variants = SVG_VARIANTS[animal] ?? SVG_VARIANTS.fox;
  if (seed === undefined || !Number.isFinite(seed)) {
    return variants[Math.floor(Math.random() * variants.length)];
  }
  const idx = Math.abs(Math.floor(seed)) % variants.length;
  return variants[idx];
}

// ---------------------------------------------------------------------------
// Schemas
// ---------------------------------------------------------------------------

const answerSchema = z.object({
  question: z.string().max(500),
  answer: z.string().max(1000),
});

const requestSchema = z.object({
  answers: z.array(answerSchema).max(3).optional(),
});

// ---------------------------------------------------------------------------
// Route
// ---------------------------------------------------------------------------

router.post("/spirit-animal", async (req, res) => {
  const parsed = requestSchema.safeParse(req.body ?? {});
  if (!parsed.success) {
    res.status(400).json({ error: "Invalid request body" });
    return;
  }

  const { answers } = parsed.data;

  try {
    // -----------------------------------------------------------------------
    // Mode 1 — return quiz questions
    // -----------------------------------------------------------------------
    if (!answers || answers.length === 0) {
      const response = await ai.models.generateContent({
        model: MODEL,
        contents: [
          {
            role: "user",
            parts: [
              {
                text: `You are helping someone discover their spirit animal guide. Generate exactly 3 multiple-choice quiz questions that explore the person's personality, values, and connection to nature. The questions should feel warm and introspective, not clinical. Each question should be 1–2 sentences with exactly 4 answer choices. Make each question count — they should cover distinct dimensions (e.g. temperament, values, instincts). Keep each choice short (2–6 words).

Return ONLY a JSON array of 3 objects, each with "question" (string) and "choices" (array of 4 strings). Example format:
[{"question":"Question text?","choices":["Choice A","Choice B","Choice C","Choice D"]}]`,
              },
            ],
          },
        ],
        config: { maxOutputTokens: 8192, responseMimeType: "application/json" },
      });

      const raw = response.text ?? "[]";
      let questions: { question: string; choices: string[] }[] = [];
      try {
        const arrayMatch = raw.match(/\[[\s\S]*\]/);
        questions = JSON.parse(arrayMatch ? arrayMatch[0] : raw);
        if (!Array.isArray(questions) || questions.length < 3) {
          throw new Error("Expected array of 3 questions");
        }
        questions = questions.slice(0, 3).map((q) => ({
          question: q.question,
          choices: Array.isArray(q.choices) ? q.choices.slice(0, 4) : [],
        }));
        if (questions.some((q) => !q.question || q.choices.length < 2)) {
          throw new Error("Malformed question object");
        }
      } catch {
        res.status(500).json({ error: "Failed to parse questions from AI" });
        return;
      }

      res.json({ questions });
      return;
    }

    // -----------------------------------------------------------------------
    // Mode 2 — evaluate answers and select spirit animal + variant
    // -----------------------------------------------------------------------
    const answersText = answers
      .map((a, i) => `Q${i + 1}: ${a.question}\nA: ${a.answer}`)
      .join("\n\n");

    const animalList = ANIMALS.join(", ");

    const evalResponse = await ai.models.generateContent({
      model: MODEL,
      contents: [
        {
          role: "user",
          parts: [
            {
              text: `You are a spirit animal guide selector. Based on the following quiz answers, select the single best-fit spirit animal from this list: ${animalList}.

Quiz answers:
${answersText}

Return ONLY a JSON object with exactly these fields:
{
  "animal": "<animal name from the list above>",
  "description": "<one sentence describing this person's spirit animal and why it fits them, written directly to the person as 'Your spirit animal is...' >",
  "variant": <integer from 0 to 2 — choose a different number each time this is called to provide variety>
}

The animal must be one of: ${animalList}. No other animals are allowed.`,
            },
          ],
        },
      ],
      config: { maxOutputTokens: 8192, responseMimeType: "application/json" },
    });

    const evalRaw = evalResponse.text ?? "{}";
    let result: { animal: string; description: string; variant?: number };
    try {
      const objMatch = evalRaw.match(/\{[\s\S]*\}/);
      result = JSON.parse(objMatch ? objMatch[0] : evalRaw);
      if (!result.animal || !result.description) {
        throw new Error("Missing fields");
      }
      result.animal = result.animal.toLowerCase().trim();
      if (!ANIMALS.includes(result.animal)) {
        result.animal = ANIMALS[0];
      }
    } catch {
      res.status(500).json({ error: "Failed to parse animal selection from AI" });
      return;
    }

    const svg = pickVariant(result.animal, result.variant);

    res.json({
      animal: result.animal,
      description: result.description,
      svg,
    });
  } catch (err) {
    console.error("spirit-animal error", err);
    res.status(500).json({ error: "AI request failed" });
  }
});

export default router;
